#include <bits/stdc++.h>
using namespace std;
const int N=30005;
int f[N],front[N],num[N],x,y,n,t;
int fa(int x)
{
    if(f[x]==x) return x;
    int fx=fa(f[x]);
    front[x]+=front[f[x]];
    return f[x]=fx;
}
int main()
{
    cin>>t;
    for(int i=1;i<=30000;i++)
    {
        f[i]=i;
        front[i]=0;
        num[i]=1;
    }
    while(t--)
    {
        string c;
        cin>>c>>x>>y;
        int fx=fa(x),fy=fa(y);
        if(c=="M")
        {
            front[fx]+=num[fy];
            f[fx]=fy;
            num[fy]+=num[fx];
            num[fx]=0;
        }
        else
        {
            if(fx!=fy) cout<<"-1\n";
            else cout<<abs(front[x]-front[y])-1<<'\n';
        }
    }
    return 0;
}
